    17	    /// Creates an object factory ctor if possible,
    18	    /// tries to use an accessible parameterless ctor otherwise.
    19	    /// </summary>
    20	    public bool TryBuild(ITypeSymbol source, ITypeSymbol target, [NotNullWhen(true)] out IInstanceConstructor? constructor)
    21	    {
    22	        return TryBuildObjectFactory(source, target, out constructor) || TryBuildParameterless(target, out constructor);
    23	    }
