    25	    /// <summary>
    26	    /// Tries to build an object factory constructor.
    27	    /// </summary>
    28	    public bool TryBuildObjectFactory(ITypeSymbol source, ITypeSymbol target, [NotNullWhen(true)] out IInstanceConstructor? constructor)
    29	    {
    30	        if (objectFactories.TryFindObjectFactory(source, target, out var factory))
    31	        {
    32	            constructor = new ObjectFactoryConstructorAdapter(factory, source, target);
    33	            return true;
    34	        }
    35	
    36	        constructor = null;
    37	        return false;
    38	    }
