    41	    /// Tries to build a parameterless constructor.
    42	    /// </summary>
    43	    public bool TryBuildParameterless(ITypeSymbol type, [NotNullWhen(true)] out IInstanceConstructor? ctor)
    44	    {
    45	        if (type is not INamedTypeSymbol namedType || namedType.IsAbstract)
    46	        {
    47	            ctor = null;
    48	            return false;
    49	        }
    50	
    51	        var ctorMethod = namedType.InstanceConstructors.FirstOrDefault(x =>
    52	            x.Parameters.IsDefaultOrEmpty && symbolAccessor.IsConstructorAccessible(x)
    53	        );
    54	        if (ctorMethod == null)
    55	        {
    56	            ctor = null;
    57	            return false;
    58	        }
    59	
    60	        ctor = BuildForConstructor(ctorMethod);
    61	        return true;
    62	    }
    63	
    64	    /// <summary>
    65	    /// Builds a parameterless ctor,
    66	    /// throws if no accessible parameterless ctor is available.
    67	    /// </summary>
    68	    public IInstanceConstructor BuildParameterless(ITypeSymbol type) =>
    69	        BuildForConstructor(((INamedTypeSymbol)type).InstanceConstructors.First(x => x.Parameters.IsDefaultOrEmpty));
