    71	    /// <summary>
    72	    /// Builds an <see cref="IInstanceConstructor"/> for a given constructor method.
    73	    /// </summary>
    74	    public IInstanceConstructor BuildForConstructor(IMethodSymbol ctor)
    75	    {
    76	        Debug.Assert(ctor.MethodKind == MethodKind.Constructor);
    77	        if (symbolAccessor.IsDirectlyAccessible(ctor))
    78	            return new InstanceConstructor(ctor.ContainingType);
    79	
    80	        Debug.Assert(symbolAccessor.IsConstructorAccessible(ctor));
    81	        return unsafeAccessorContext.GetOrBuildConstructor(ctor);
    82	    }
    83	}
