   248	        var targetMemberGetter = targetMemberPath.BuildGetter(ctx.BuilderContext);
   249	        var memberMapping = new MemberExistingTargetMapping(
   250	            existingTargetMapping,
   251	            sourceMemberGetter,
   252	            targetMemberGetter,
   253	            memberMappingInfo
   254	        );
   255	        ctx.AddMemberAssignmentMapping(memberMapping);
   256	        return true;
   257	    }
